
'use client';

import * as React from 'react';
import { mockProjects, mockUsers } from '@/lib/mock-data';
import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import type { Project, User } from '@/lib/types';
import Link from 'next/link';

export default function SolicitudesPage() {
  const [currentUser, setCurrentUser] = React.useState<User | null>(null);

  React.useEffect(() => {
    const storedUser = localStorage.getItem('proconecta_user');
    if (storedUser) {
      setCurrentUser(JSON.parse(storedUser));
    }
  }, []);

  if (!currentUser) {
    return <div>Cargando...</div>;
  }

  const userProjects = mockProjects.filter(
    (p) => p.solicitante.id === currentUser.id
  );

  const draftProjects = userProjects.filter((p) => p.status === 'Draft');
  const rejectedProjects = userProjects.filter(
    (p) => p.status === 'Rejected with feedback'
  );

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-bold font-headline">
          Catálogo de sus solicitudes
        </h1>
        <p className="text-muted-foreground">
          Gestione sus proyectos enviados y borradores.
        </p>
      </div>

      <div className="space-y-6">
        <h2 className="text-2xl font-semibold">Borradores</h2>
        {draftProjects.length > 0 ? (
          <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            {draftProjects.map((project) => (
              <Card key={project.id}>
                <CardHeader>
                  <CardTitle>{project.title}</CardTitle>
                </CardHeader>
                <CardFooter>
                  <Button asChild>
                    <Link href={`/projects/${project.id}/edit`}>Editar</Link>
                  </Button>
                </CardFooter>
              </Card>
            ))}
          </div>
        ) : (
          <p className="text-muted-foreground">
            No tiene borradores de proyectos.
          </p>
        )}
      </div>

      <div className="space-y-6">
        <h2 className="text-2xl font-semibold">Rechazadas</h2>
        {rejectedProjects.length > 0 ? (
          <div className="space-y-4">
            {rejectedProjects.map((project) => (
              <Card key={project.id}>
                 <CardHeader>
                  <CardTitle>{project.title}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="font-semibold">Retroalimentación:</p>
                  <p className="text-muted-foreground">
                    Revisar la sección de presupuesto y objetivos. Falta detalle en el cronograma.
                  </p>
                </CardContent>
                <CardFooter>
                  <Button asChild>
                    <Link href={`/projects/${project.id}/edit`}>Editar</Link>
                  </Button>
                </CardFooter>
              </Card>
            ))}
          </div>
        ) : (
          <p className="text-muted-foreground">
            No tiene proyectos rechazados.
          </p>
        )}
      </div>
    </div>
  );
}
